int should_keep_alive(const http_request_t *req) {
const char *conn = get_header(req, "connection");
if (conn) {
if (strcasecmp(conn, "close")      == 0) return 0; // explicit close
if (strcasecmp(conn, "keep-alive") == 0) return 1; // explicit keep
}
// No Connection header: use HTTP version default
return (strcmp(req->version, "HTTP/1.1") == 0) ? 1 : 0;
}
